SELECT * FROM (SELECT l_shipmode,sum(CASE WHEN o_orderpriORity = '1-URGENT' OR o_orderpriority = '2-HIGH' THEN 1 ELSE 0 END) AS high_line_count, sum(CASE WHEN o_orderpriORity <> '1-URGENT' AND o_orderpriORity <> '2-HIGH' THEN 1 ELSE 0 END) AS low_line_count FROM orders, lineitem WHERE o_orderkey = l_orderkey AND (l_shipmode = 'MAIL' OR l_shipmode = 'SHIP') AND l_commitdate < l_receiptdate AND l_shipdate < l_commitdate AND l_receiptdate >= TO_DATE('1994-01-01', 'YYYY-MM-DD') AND l_receiptdate < TO_DATE('1995-01-01', 'YYYY-MM-DD') GROUP BY l_shipmode) l ORDER BY l_shipmode;
